import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"第 10 章：混合查询管线","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/10-hybrid-pipeline.md","filePath":"chapters/10-hybrid-pipeline.md"}'),d={name:"chapters/10-hybrid-pipeline.md"};function n(i,e,s,c,h,l){return t(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="第-10-章-混合查询管线" tabindex="-1">第 10 章：混合查询管线 <a class="header-anchor" href="#第-10-章-混合查询管线" aria-label="Permalink to &quot;第 10 章：混合查询管线&quot;">​</a></h1><blockquote><p><code>hybridQuery()</code> 是 qmd 检索系统的心脏——一条八步管线将 BM25 全文检索、向量语义搜索、LLM 查询扩展和交叉编码器重排熔于一炉，在延迟与召回之间走出了一条务实的中间路线。</p></blockquote><h2 id="管线全景" tabindex="-1">管线全景 <a class="header-anchor" href="#管线全景" aria-label="Permalink to &quot;管线全景&quot;">​</a></h2><p><code>hybridQuery()</code> 函数跨越近 280 行，是 <code>src/store.ts</code> 中最长的单一函数。它接收用户原始查询、可选的 <code>intent</code> 字符串以及各种限制参数，返回 <code>HybridQueryResult[]</code>。整条管线可以拆解为八个有序阶段：BM25 探针、查询扩展、分型路由搜索、RRF 融合、分块选择、重排、位置感知混合、去重过滤。</p><p>每个阶段都有明确的短路或跳过条件，这使得简单查询可以在几毫秒内返回，而模糊查询则自动启用全链路。理解这八步之间的数据流动，就等于理解了 qmd 检索的全部核心逻辑。</p><h2 id="第一步-bm25-探针" tabindex="-1">第一步：BM25 探针 <a class="header-anchor" href="#第一步-bm25-探针" aria-label="Permalink to &quot;第一步：BM25 探针&quot;">​</a></h2><h3 id="强信号检测" tabindex="-1">强信号检测 <a class="header-anchor" href="#强信号检测" aria-label="Permalink to &quot;强信号检测&quot;">​</a></h3><p>管线的第一步不是盲目展开搜索，而是先用 FTS（全文搜索）做一次快速试探。<code>hybridQuery()</code> 在第 3738 行发起一次标准 BM25 查询，拿到初始结果列表后，检查两个常量阈值：</p><div class="language-ts vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/store.ts L226-232</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> STRONG_SIGNAL_MIN_SCORE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.85</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> STRONG_SIGNAL_MIN_GAP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.15</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>判断逻辑非常直觉：如果第一名的 BM25 得分 ≥ 0.85，<strong>且</strong>与第二名的分差 ≥ 0.15，则认为这是一个&quot;强信号&quot;。强信号意味着 FTS 已经高度自信地找到了目标文档，后续昂贵的 LLM 扩展和向量搜索可以安全跳过。</p><h3 id="为什么-intent-会禁用旁路" tabindex="-1">为什么 intent 会禁用旁路 <a class="header-anchor" href="#为什么-intent-会禁用旁路" aria-label="Permalink to &quot;为什么 intent 会禁用旁路&quot;">​</a></h3><p>这里有一个关键的设计细节：当调用方传入了 <code>intent</code> 参数时，即使 BM25 探针检测到强信号，旁路也会被<strong>禁用</strong>。原因在于，带 intent 的查询往往是模糊的——用户说&quot;性能&quot;，intent 说&quot;网页加载时间&quot;，BM25 可能匹配到体育成绩相关的文档，表面得分很高但语义完全错误。此时必须让向量路径参与纠偏。</p><p>如果命中强信号且无 intent，<code>SearchHooks.onStrongSignal</code> 回调被触发（第 3741 行），CLI 可以据此输出提示信息，让用户知道搜索走了快速路径。</p><h2 id="第二步-查询扩展" tabindex="-1">第二步：查询扩展 <a class="header-anchor" href="#第二步-查询扩展" aria-label="Permalink to &quot;第二步：查询扩展&quot;">​</a></h2><p>当强信号未被检测到（或被 intent 禁用）时，管线进入 <code>expandQuery()</code> 调用。这一步通过 LLM 生成多个查询变体，分为三种类型：<code>lex</code>（关键词变体）、<code>vec</code>（语义变体）和 <code>hyde</code>（假设性文档）。</p><p>扩展的细节将在第 11 章详述。这里需要注意的是，<code>expandQuery()</code> 本身带有缓存机制，相同的查询 + 模型 + intent 组合不会重复调用 LLM。扩展结果会被过滤，去掉与原始查询完全相同的变体，避免重复搜索。</p><p><code>SearchHooks.onExpandStart</code> 和 <code>onExpand</code> 回调分别在扩展开始和完成时触发，CLI 用它们来显示&quot;正在扩展查询...&quot;之类的进度提示。</p><h2 id="第三步-分型路由搜索" tabindex="-1">第三步：分型路由搜索 <a class="header-anchor" href="#第三步-分型路由搜索" aria-label="Permalink to &quot;第三步：分型路由搜索&quot;">​</a></h2><p>这一步是管线中计算量最大的环节，也是 qmd 混合检索&quot;混合&quot;二字的核心所在。所有扩展结果根据类型被路由到不同的搜索引擎：</p><table tabindex="0"><thead><tr><th>扩展类型</th><th>目标引擎</th><th>执行方式</th></tr></thead><tbody><tr><td><code>lex</code></td><td>FTS 全文搜索</td><td>同步执行，毫秒级</td></tr><tr><td><code>vec</code></td><td>sqlite-vec 向量搜索</td><td>批量嵌入后查询</td></tr><tr><td><code>hyde</code></td><td>sqlite-vec 向量搜索</td><td>批量嵌入后查询</td></tr></tbody></table><p>关键性能决策在于<strong>批量嵌入</strong>：原始查询与所有 <code>vec</code>、<code>hyde</code> 变体被收集到一个数组中，通过 <code>embedBatch()</code> 一次性发送给嵌入模型。这比逐条嵌入快得多——假设有 4 个向量变体，批量方式只需一次网络往返，而逐条方式需要 4 次。</p><p>FTS 搜索在本地 SQLite 上执行，延迟在个位数毫秒级别，所以可以同步完成。向量搜索依赖 sqlite-vec 扩展，使用预先计算好的文档嵌入向量做近似最近邻查找。</p><h2 id="第四步-rrf-融合" tabindex="-1">第四步：RRF 融合 <a class="header-anchor" href="#第四步-rrf-融合" aria-label="Permalink to &quot;第四步：RRF 融合&quot;">​</a></h2><p>多路搜索产生多个排序列表，需要一种方式将它们合并。qmd 使用的是经典的 <strong>Reciprocal Rank Fusion</strong>（RRF）算法，实现在 <code>reciprocalRankFusion()</code> 函数中。</p><h3 id="reciprocalrankfusion-的实现" tabindex="-1">reciprocalRankFusion() 的实现 <a class="header-anchor" href="#reciprocalrankfusion-的实现" aria-label="Permalink to &quot;reciprocalRankFusion() 的实现&quot;">​</a></h3><p>该函数接收一个带权重的列表数组 <code>Array&lt;{results, weight}&gt;</code>，内部使用 <code>Map&lt;string, { result, rrfScore, topRank }&gt;</code> 做累积。对每个列表中排名为 <code>rank</code> 的文档，累加公式为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>score += weight / (k + rank + 1)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其中 <code>k = 60</code> 是标准 RRF 常数。权重的设置很有讲究：前两个列表（通常是原始查询的 FTS 和向量结果）获得 <strong>2 倍权重</strong>，因为原始查询本身最能代表用户意图，扩展变体只是补充。</p><p>此外还有一个<strong>顶部排名加分</strong>机制：如果某个文档在任何一个列表中排名第 1，额外加 0.05 分；排名第 2 或第 3，额外加 0.02 分。这奖励了那些在至少一个检索维度上表现突出的文档，使它们不容易被平均化淹没。</p><h2 id="第五步-分块选择" tabindex="-1">第五步：分块选择 <a class="header-anchor" href="#第五步-分块选择" aria-label="Permalink to &quot;第五步：分块选择&quot;">​</a></h2><p>这一步是管线中最精巧的性能优化。RRF 融合后我们有了候选文档列表，但直接把完整文档体送去重排的代价是 <strong>O(tokens)</strong>——一篇 5000 字的文档会消耗大量 reranker 计算。</p><p>qmd 的解决方案是：对每个候选文档，调用 <code>chunkDocument()</code> 将正文切成若干块，然后用关键词重叠度选出<strong>最佳块</strong>。重叠度的计算结合了两种来源：</p><ul><li>查询本身的分词（权重 1.0）</li><li>intent 中提取的术语（权重 0.5，通过 <code>INTENT_WEIGHT_CHUNK</code> 常量控制）</li></ul><p>intent 术语的权重设为 0.5 而非 1.0，是因为 intent 是对查询方向的补充说明，不应完全主导块的选择。最终每个候选文档只保留一个最佳块（<code>bestChunk</code>）及其在文档中的位置（<code>bestChunkPos</code>），送入下一步。</p><p>这个&quot;先粗选文档，再精选块&quot;的两级策略，是 qmd 检索延迟能控制在可接受范围内的关键。<code>RERANK_CANDIDATE_LIMIT = 40</code>（第 232 行）进一步限制了进入块选择的候选数量。</p><h2 id="第六步-重排" tabindex="-1">第六步：重排 <a class="header-anchor" href="#第六步-重排" aria-label="Permalink to &quot;第六步：重排&quot;">​</a></h2><p>最佳块（而非完整文档体）被送入 <code>rerank()</code> 函数。重排使用交叉编码器模型，能够理解查询与文档之间的深层语义关系，弥补 BM25 和向量检索在精细排序上的不足。</p><p>重排只处理块文本，这意味着即使有 40 个候选，每个块平均 200-300 token，总输入也只有 8000-12000 token——远小于直接重排完整文档的开销。<code>rerank()</code> 的具体实现将在第 11 章展开。</p><h2 id="第七步-位置感知混合" tabindex="-1">第七步：位置感知混合 <a class="header-anchor" href="#第七步-位置感知混合" aria-label="Permalink to &quot;第七步：位置感知混合&quot;">​</a></h2><p>这一步是 qmd 检索管线中最具原创性的设计。重排完成后，需要将 RRF 分数和 reranker 分数融合成最终得分。朴素做法是固定权重线性加权，但 qmd 采用了<strong>根据 RRF 排名动态调整权重</strong>的策略：</p><table tabindex="0"><thead><tr><th>RRF 排名</th><th>rrfWeight</th></tr></thead><tbody><tr><td>前 3 名</td><td>0.75</td></tr><tr><td>第 4-10 名</td><td>0.60</td></tr><tr><td>第 11 名及以后</td><td>0.40</td></tr></tbody></table><p>最终混合公式为：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>blendedScore = rrfWeight * (1 / rrfRank) + (1 - rrfWeight) * rerankScore</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="设计动机" tabindex="-1">设计动机 <a class="header-anchor" href="#设计动机" aria-label="Permalink to &quot;设计动机&quot;">​</a></h3><p>为什么排名靠前的文档要给 RRF 更高的权重？因为 RRF 排名靠前意味着该文档在<strong>多个检索维度</strong>上都表现良好，这种一致性本身就是强烈的相关性信号。如果 reranker 对这些文档给出低分，更可能是 reranker 的片面判断（比如块选择不理想），而非文档真的不相关。</p><p>相反，RRF 排名靠后的文档只在少数维度上被召回，此时应该更信任 reranker 的精细判断，所以 reranker 权重升高到 0.60。这种&quot;位置感知&quot;策略有效地保护了多路一致的好结果，同时给 reranker 在长尾区域留出了足够的调整空间。</p><h2 id="第八步-去重与过滤" tabindex="-1">第八步：去重与过滤 <a class="header-anchor" href="#第八步-去重与过滤" aria-label="Permalink to &quot;第八步：去重与过滤&quot;">​</a></h2><p>最后一步相对简单：按文件路径去重（同一文件只保留得分最高的条目），应用 <code>minScore</code> 阈值过滤低分结果，然后按 <code>limit</code> 参数截取最终返回数量。</p><h2 id="返回类型与进度钩子" tabindex="-1">返回类型与进度钩子 <a class="header-anchor" href="#返回类型与进度钩子" aria-label="Permalink to &quot;返回类型与进度钩子&quot;">​</a></h2><h3 id="hybridqueryresult" tabindex="-1">HybridQueryResult <a class="header-anchor" href="#hybridqueryresult" aria-label="Permalink to &quot;HybridQueryResult&quot;">​</a></h3><p>返回类型包含了检索全链路的关键信息：<code>file</code>（文件路径）、<code>displayPath</code>（显示路径）、<code>title</code>、<code>body</code>（完整文档体）、<code>bestChunk</code>（最佳块文本）、<code>bestChunkPos</code>（块在文档中的起止位置）、<code>score</code>（最终混合得分）、<code>context</code>（上下文信息）、<code>docid</code>，以及可选的 <code>explain</code> 追踪字段用于调试。</p><h3 id="searchhooks" tabindex="-1">SearchHooks <a class="header-anchor" href="#searchhooks" aria-label="Permalink to &quot;SearchHooks&quot;">​</a></h3><p><code>SearchHooks</code> 接口定义了管线各阶段的进度回调：<code>onStrongSignal</code>、<code>onExpandStart</code>、<code>onExpand</code>、<code>onEmbedStart</code>、<code>onEmbedDone</code>、<code>onRerankStart</code>、<code>onRerankDone</code>。这些回调让 CLI 能够在长时间运行的搜索过程中实时展示进度，而不是让用户面对一片空白等待。</p><p>这种 hooks 设计将 I/O 表现与核心逻辑解耦——<code>hybridQuery()</code> 本身不关心进度如何展示，它只在合适的时机调用回调函数，具体的 UI 行为由调用方决定。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p><code>hybridQuery()</code> 的八步管线体现了一种&quot;分层递进&quot;的检索哲学：先用最便宜的 BM25 试探，能短路就短路；不能短路则用 LLM 扩展查询空间，再通过分型路由最大化召回；RRF 融合将多路结果统一排序；分块选择把重排开销从 O(文档) 降到 O(块)；位置感知混合在 RRF 的全局视野与 reranker 的局部精度之间取得平衡。每一步都有明确的性能理由，每一个阈值都服务于延迟与质量的权衡。理解了这条管线，就掌握了 qmd 检索系统的核心脉络。</p>`,56)])])}const k=a(d,[["render",n]]);export{u as __pageData,k as default};
